package com.socialblog.comment.domain;import jakarta.persistence.*;import java.time.Instant;import java.util.UUID;
@Entity @Table(name="article_projection")public class ArticleProjection{@Id @Column(name="article_id")private UUID articleId;@Column(nullable=false)private boolean active;@Column(name="author_id")private UUID authorId;@Column(name="updated_at",nullable=false)private Instant updatedAt;protected ArticleProjection(){}public ArticleProjection(UUID id,boolean value){this(id,value,null);}public ArticleProjection(UUID id,boolean value,UUID author){articleId=id;update(value,author);}public void update(boolean value,UUID author){active=value;if(author!=null)authorId=author;updatedAt=Instant.now();}public void setActive(boolean value){update(value,null);}public boolean isActive(){return active;}public UUID getArticleId(){return articleId;}public UUID getAuthorId(){return authorId;}}
